1553		if interfaces, err := net.Interfaces(); err == nil {
1554			for _, iface := range interfaces {
1555				addrs, err := iface.Addrs()
1556				if err != nil {
1557					continue
1558				}
1559	
1560				for _, a := range addrs {
1561					if parsed, _, err := net.ParseCIDR(a.String()); err == nil {
1562						if parsed.String() == ip.String() {
1563							return true
1564						}
1565					}
1566				}
1567			}
1568		}
1569	
1570		return false
1571	}
