### 11. MANIFEST MANAGEMENT

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775489911601-q4vnve/manifest/manifest.go` (lines 16-110)

The `Manifest` struct represents a model's metadata:

```go
type Manifest struct {
	SchemaVersion int     `json:"schemaVersion"`
	MediaType     string  `json:"mediaType"`
	Config        Layer   `json:"config"`          // Model configuration blob
	Layers        []Layer `json:"layers"`          // Model weight layers
	filepath string                                  // Path to manifest file
	fi       os.FileInfo
	digest   string
}

func (m *Manifest) Remove() error {
	// Removes the manifest file itself
	if err := os.Remove(m.filepath); err != nil {
		return err
	}
	manifests, err := manifest.Path()
	if err != nil {
		return err
	}
	return PruneDirectory(manifests)
}

func (m *Manifest) RemoveLayers() error {
	// Removes layers that are no longer used by any manifest
	// Implements reference counting - only deletes if no other manifest uses the layer
	ms, err := Manifests(true)
	if err != nil {
		return err
	}

	// Build set of digests still in use by other manifests
	inUse := make(map[string]struct{})
	for _, other := range ms {
		for _, layer := range append(other.Layers, other.Config) {
			if layer.Digest != "" {
				inUse[layer.Digest] = struct{}{}
			}
		}
	}

	// Remove layers not used by any other manifest
	for _, layer := range append(m.Layers, m.Config) {
		if layer.Digest == "" {
			continue
		}
		if _, used := inUse[layer.Digest]; used {
			continue
		}
		blob, err := BlobsPath(layer.Digest)
		if err != nil {
			return err
		}
		if err := os.Remove(blob); os.IsNotExist(err) {
			slog.Debug("layer does not exist", "digest", layer.Digest)
		} else if err != nil {
			return err
		}
	}

	return nil
}
